  1→import React, { useState, useEffect, useCallback } from 'react';
  2→import { authenticatedGet } from '../utils/auth';
  3→import {
  4→    listSharingRules,
  5→    createSharingRule,
  6→    deleteSharingRule,
  7→    type AwsAccountSharing,
  8→} from '../services/awsAccountSharingService';
  9→
 10→interface User {
 11→    id: number;
 12→    username: string;
 13→    email: string;
 14→    roles: string[];
 15→}
 16→
 17→const AwsAccountSharingManager: React.FC = () => {
 18→    const [sharingRules, setSharingRules] = useState<AwsAccountSharing[]>([]);
 19→    const [users, setUsers] = useState<User[]>([]);
 20→    const [isLoading, setIsLoading] = useState(true);
 21→    const [error, setError] = useState<string | null>(null);
 22→    const [successMessage, setSuccessMessage] = useState<string | null>(null);
 23→
 24→    // Pagination
 25→    const [page, setPage] = useState(0);
 26→    const [totalPages, setTotalPages] = useState(0);
 27→    const [totalElements, setTotalElements] = useState(0);
 28→    const pageSize = 20;
 29→
 30→    // Create form
 31→    const [showCreateForm, setShowCreateForm] = useState(false);
 32→    const [sourceUserId, setSourceUserId] = useState<number | ''>('');
 33→    const [targetUserId, setTargetUserId] = useState<number | ''>('');
 34→    const [isCreating, setIsCreating] = useState(false);
 35→
 36→    // Delete confirmation
 37→    const [deletingId, setDeletingId] = useState<number | null>(null);
 38→
 39→    const showSuccess = (msg: string) => {
 40→        setSuccessMessage(msg);
 41→        setTimeout(() => setSuccessMessage(null), 5000);
 42→    };
 43→
 44→    const showError = (msg: string) => {
 45→        setError(msg);
 46→        setTimeout(() => setError(null), 8000);
 47→    };
 48→
 49→    const fetchSharingRules = useCallback(async () => {
 50→        try {
 51→            setIsLoading(true);
 52→            const result = await listSharingRules(page, pageSize);
 53→            setSharingRules(result.content);
 54→            setTotalPages(result.totalPages);
 55→            setTotalElements(result.totalElements);
 56→        } catch (err: any) {
 57→            showError(err.message || 'Failed to load sharing rules');
 58→        } finally {
 59→            setIsLoading(false);
 60→        }
 61→    }, [page]);
 62→
 63→    const fetchUsers = useCallback(async () => {
 64→        try {
 65→            const response = await authenticatedGet('/api/users');
 66→            if (response.ok) {
 67→                const data = await response.json();
 68→                setUsers(data);
 69→            }
 70→        } catch {
 71→            // Non-critical - user dropdowns will be empty
 72→        }
 73→    }, []);
 74→
 75→    useEffect(() => {
 76→        fetchSharingRules();
 77→        fetchUsers();
 78→    }, [fetchSharingRules, fetchUsers]);
 79→
 80→    const handleCreate = async (e: React.FormEvent) => {
 81→        e.preventDefault();
 82→        if (sourceUserId === '' || targetUserId === '') {
 83→            showError('Please select both source and target users');
 84→            return;
 85→        }
 86→        if (sourceUserId === targetUserId) {
 87→            showError('Source and target user cannot be the same');
 88→            return;
 89→        }
 90→
 91→        setIsCreating(true);
 92→        try {
 93→            const result = await createSharingRule({
 94→                sourceUserId: sourceUserId as number,
 95→                targetUserId: targetUserId as number,
 96→            });
 97→            showSuccess(
 98→                `Sharing rule created: ${result.sourceUserEmail} -> ${result.targetUserEmail} (${result.sharedAwsAccountCount} accounts)`
 99→            );
100→            setShowCreateForm(false);
101→            setSourceUserId('');
102→            setTargetUserId('');
103→            fetchSharingRules();
104→        } catch (err: any) {
105→            showError(err.message || 'Failed to create sharing rule');
106→        } finally {
107→            setIsCreating(false);
108→        }
109→    };
110→
111→    const handleDelete = async (id: number) => {
112→        try {
113→            await deleteSharingRule(id);
114→            showSuccess('Sharing rule deleted successfully');
115→            setDeletingId(null);
116→            fetchSharingRules();
117→        } catch (err: any) {
118→            showError(err.message || 'Failed to delete sharing rule');
119→        }
120→    };
121→
122→    const formatDate = (dateStr: string) => {
123→        try {
124→            return new Date(dateStr).toLocaleString();
125→        } catch {
126→            return dateStr;
127→        }
128→    };
129→
130→    return (
131→        <div>
132→            <div className="d-flex justify-content-between align-items-center mb-3">
133→                <h2>
134→                    <i className="bi bi-share-fill me-2"></i>
135→                    AWS Account Sharing
136→                </h2>
137→                <button
138→                    className="btn btn-primary"
139→                    onClick={() => setShowCreateForm(!showCreateForm)}
140→                >
141→                    <i className={`bi ${showCreateForm ? 'bi-x-lg' : 'bi-plus-lg'} me-1`}></i>
142→                    {showCreateForm ? 'Cancel' : 'Create Sharing Rule'}
143→                </button>
144→            </div>
145→
146→            <p className="text-muted mb-3">
147→                Share AWS account visibility between users. When User A's accounts are shared with User B,
148→                User B can see all assets belonging to User A's AWS accounts. Sharing is directional and non-transitive.
149→            </p>
150→
151→            {/* Alerts */}
152→            {successMessage && (
153→                <div className="alert alert-success alert-dismissible fade show" role="alert">
154→                    {successMessage}
155→                    <button type="button" className="btn-close" onClick={() => setSuccessMessage(null)}></button>
156→                </div>
157→            )}
158→            {error && (
159→                <div className="alert alert-danger alert-dismissible fade show" role="alert">
160→                    {error}
161→                    <button type="button" className="btn-close" onClick={() => setError(null)}></button>
162→                </div>
163→            )}
164→
165→            {/* Create Form */}
166→            {showCreateForm && (
167→                <div className="card mb-4">
168→                    <div className="card-body">
169→                        <h5 className="card-title">Create Sharing Rule</h5>
170→                        <form onSubmit={handleCreate}>
171→                            <div className="row g-3">
172→                                <div className="col-md-5">
173→                                    <label htmlFor="sourceUser" className="form-label">
174→                                        Source User (shares their AWS accounts)
175→                                    </label>
176→                                    <select
177→                                        id="sourceUser"
178→                                        className="form-select"
179→                                        value={sourceUserId}
180→                                        onChange={(e) => setSourceUserId(e.target.value ? Number(e.target.value) : '')}
181→                                        required
182→                                    >
183→                                        <option value="">-- Select source user --</option>
184→                                        {users.map((user) => (
185→                                            <option key={user.id} value={user.id}>
186→                                                {user.username} ({user.email})
187→                                            </option>
188→                                        ))}
189→                                    </select>
190→                                </div>
191→                                <div className="col-md-1 d-flex align-items-end justify-content-center pb-2">
192→                                    <i className="bi bi-arrow-right fs-4"></i>
193→                                </div>
194→                                <div className="col-md-5">
195→                                    <label htmlFor="targetUser" className="form-label">
196→                                        Target User (receives visibility)
197→                                    </label>
198→                                    <select
199→                                        id="targetUser"
200→                                        className="form-select"
201→                                        value={targetUserId}
202→                                        onChange={(e) => setTargetUserId(e.target.value ? Number(e.target.value) : '')}
203→                                        required
204→                                    >
205→                                        <option value="">-- Select target user --</option>
206→                                        {users.map((user) => (
207→                                            <option key={user.id} value={user.id}>
208→                                                {user.username} ({user.email})
209→                                            </option>
210→                                        ))}
211→                                    </select>
212→                                </div>
213→                                <div className="col-md-1 d-flex align-items-end">
214→                                    <button
215→                                        type="submit"
216→                                        className="btn btn-success"
217→                                        disabled={isCreating}
218→                                    >
219→                                        {isCreating ? (
220→                                            <span className="spinner-border spinner-border-sm me-1"></span>
221→                                        ) : (
222→                                            <i className="bi bi-check-lg me-1"></i>
223→                                        )}
224→                                        Create
225→                                    </button>
226→                                </div>
227→                            </div>
228→                        </form>
229→                    </div>
230→                </div>
231→            )}
232→
233→            {/* Table */}
234→            {isLoading ? (
235→                <div className="text-center py-4">
236→                    <div className="spinner-border" role="status">
237→                        <span className="visually-hidden">Loading...</span>
238→                    </div>
239→                </div>
240→            ) : sharingRules.length === 0 ? (
241→                <div className="alert alert-info">
242→                    No AWS account sharing rules configured. Click "Create Sharing Rule" to add one.
243→                </div>
244→            ) : (
245→                <>
246→                    <div className="table-responsive">
247→                        <table className="table table-striped table-hover">
248→                            <thead className="table-dark">
249→                                <tr>
250→                                    <th>Source User</th>
251→                                    <th>Target User</th>
252→                                    <th>Shared Accounts</th>
253→                                    <th>Created By</th>
254→                                    <th>Created At</th>
255→                                    <th>Actions</th>
256→                                </tr>
257→                            </thead>
258→                            <tbody>
259→                                {sharingRules.map((rule) => (
260→                                    <tr key={rule.id}>
261→                                        <td>
262→                                            <strong>{rule.sourceUserUsername}</strong>
263→                                            <br />
264→                                            <small className="text-muted">{rule.sourceUserEmail}</small>
265→                                        </td>
266→                                        <td>
267→                                            <strong>{rule.targetUserUsername}</strong>
268→                                            <br />
269→                                            <small className="text-muted">{rule.targetUserEmail}</small>
270→                                        </td>
271→                                        <td>
272→                                            <span className="badge bg-info">{rule.sharedAwsAccountCount}</span>
273→                                        </td>
274→                                        <td>{rule.createdByUsername}</td>
275→                                        <td>{formatDate(rule.createdAt)}</td>
276→                                        <td>
277→                                            {deletingId === rule.id ? (
278→                                                <div className="btn-group btn-group-sm">
279→                                                    <button
280→                                                        className="btn btn-danger"
281→                                                        onClick={() => handleDelete(rule.id)}
282→                                                    >
283→                                                        Confirm
284→                                                    </button>
285→                                                    <button
286→                                                        className="btn btn-secondary"
287→                                                        onClick={() => setDeletingId(null)}
288→                                                    >
289→                                                        Cancel
290→                                                    </button>
291→                                                </div>
292→                                            ) : (
293→                                                <button
294→                                                    className="btn btn-outline-danger btn-sm"
295→                                                    onClick={() => setDeletingId(rule.id)}
296→                                                    title="Delete sharing rule"
297→                                                >
298→                                                    <i className="bi bi-trash"></i>
299→                                                </button>
300→                                            )}
301→                                        </td>
302→                                    </tr>
303→                                ))}
304→                            </tbody>
305→                        </table>
306→                    </div>
307→
308→                    {/* Pagination */}
309→                    {totalPages > 1 && (
310→                        <nav aria-label="Sharing rules pagination">
311→                            <div className="d-flex justify-content-between align-items-center">
312→                                <span className="text-muted">
313→                                    Showing {page * pageSize + 1}-{Math.min((page + 1) * pageSize, totalElements)} of {totalElements} rules
314→                                </span>
315→                                <ul className="pagination mb-0">
316→                                    <li className={`page-item ${page === 0 ? 'disabled' : ''}`}>
317→                                        <button className="page-link" onClick={() => setPage(p => Math.max(0, p - 1))}>
318→                                            Previous
319→                                        </button>
320→                                    </li>
321→                                    {Array.from({ length: totalPages }, (_, i) => (
322→                                        <li key={i} className={`page-item ${page === i ? 'active' : ''}`}>
323→                                            <button className="page-link" onClick={() => setPage(i)}>
324→                                                {i + 1}
325→                                            </button>
326→                                        </li>
327→                                    ))}
328→                                    <li className={`page-item ${page >= totalPages - 1 ? 'disabled' : ''}`}>
329→                                        <button className="page-link" onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}>
330→                                            Next
331→                                        </button>
332→                                    </li>
333→                                </ul>
334→                            </div>
335→                        </nav>
336→                    )}
337→                </>
338→            )}
339→        </div>
340→    );
341→};
342→
343→export default AwsAccountSharingManager;
