 1→import { authenticatedGet, authenticatedPost, authenticatedDelete } from '../utils/auth';
 2→
 3→/**
 4→ * Service for AWS Account Sharing API operations.
 5→ *
 6→ * Feature: AWS Account Sharing
 7→ */
 8→
 9→export interface AwsAccountSharing {
10→    id: number;
11→    sourceUserId: number;
12→    sourceUserEmail: string;
13→    sourceUserUsername: string;
14→    targetUserId: number;
15→    targetUserEmail: string;
16→    targetUserUsername: string;
17→    createdById: number;
18→    createdByUsername: string;
19→    sharedAwsAccountCount: number;
20→    createdAt: string;
21→    updatedAt: string;
22→}
23→
24→export interface CreateAwsAccountSharingRequest {
25→    sourceUserId: number;
26→    targetUserId: number;
27→}
28→
29→export interface AwsAccountSharingListResponse {
30→    content: AwsAccountSharing[];
31→    totalElements: number;
32→    totalPages: number;
33→    page: number;
34→    size: number;
35→}
36→
37→/**
38→ * List AWS account sharing rules with pagination.
39→ */
40→export async function listSharingRules(
41→    page: number = 0,
42→    size: number = 20
43→): Promise<AwsAccountSharingListResponse> {
44→    const params = new URLSearchParams({
45→        page: page.toString(),
46→        size: size.toString()
47→    });
48→
49→    const response = await authenticatedGet(`/api/aws-account-sharing?${params.toString()}`);
50→
51→    if (!response.ok) {
52→        if (response.status === 401) throw new Error('Authentication required');
53→        if (response.status === 403) throw new Error('Insufficient permissions (ADMIN role required)');
54→        throw new Error(`Failed to list sharing rules: ${response.status}`);
55→    }
56→
57→    return await response.json();
58→}
59→
60→/**
61→ * Create a new AWS account sharing rule.
62→ */
63→export async function createSharingRule(
64→    request: CreateAwsAccountSharingRequest
65→): Promise<AwsAccountSharing> {
66→    const response = await authenticatedPost('/api/aws-account-sharing', request);
67→
68→    if (!response.ok) {
69→        const errorData = await response.json().catch(() => ({ message: 'Failed to create sharing rule' }));
70→        if (response.status === 400) throw new Error(errorData.message || 'Invalid request');
71→        if (response.status === 401) throw new Error('Authentication required');
72→        if (response.status === 403) throw new Error('Insufficient permissions (ADMIN role required)');
73→        if (response.status === 404) throw new Error(errorData.message || 'User not found');
74→        throw new Error(errorData.message || `Failed to create sharing rule: ${response.status}`);
75→    }
76→
77→    return await response.json();
78→}
79→
80→/**
81→ * Delete an AWS account sharing rule.
82→ */
83→export async function deleteSharingRule(id: number): Promise<void> {
84→    const response = await authenticatedDelete(`/api/aws-account-sharing/${id}`);
85→
86→    if (!response.ok) {
87→        if (response.status === 401) throw new Error('Authentication required');
88→        if (response.status === 403) throw new Error('Insufficient permissions (ADMIN role required)');
89→        if (response.status === 404) throw new Error('Sharing rule not found');
90→        throw new Error(`Failed to delete sharing rule: ${response.status}`);
91→    }
92→}
