  1→// Authentication utility functions
  2→//
  3→// Authentication is handled via the HttpOnly secman_auth cookie set by the backend.
  4→// The cookie is sent automatically with credentials: 'include' on fetch requests
  5→// and withCredentials: true on axios requests. No JavaScript token access needed.
  6→
  7→export interface User {
  8→    id: number;
  9→    username: string;
 10→    email: string;
 11→    roles: string[];
 12→}
 13→
 14→/**
 15→ * Get the stored user information
 16→ */
 17→export function getUser(): User | null {
 18→    if (typeof window === 'undefined') return null;
 19→    const userStr = localStorage.getItem('user');
 20→    if (!userStr) return null;
 21→
 22→    try {
 23→        return JSON.parse(userStr);
 24→    } catch (e) {
 25→        return null;
 26→    }
 27→}
 28→
 29→/**
 30→ * Check if user is currently authenticated.
 31→ * With HttpOnly cookies, we check for user data in localStorage instead of the token.
 32→ * The actual authentication is validated by the server using the HttpOnly cookie.
 33→ */
 34→export function isAuthenticated(): boolean {
 35→    // Check for user data (stored on successful login)
 36→    // The actual token is in an HttpOnly cookie, not accessible via JS
 37→    return getUser() !== null;
 38→}
 39→
 40→/**
 41→ * Check if user has a specific role or any of the specified roles
 42→ * @param role Single role string or array of roles to check
 43→ * @returns true if user has the role (or any of the roles if array)
 44→ */
 45→export function hasRole(role: string | string[]): boolean {
 46→    const user = getUser();
 47→    if (!user?.roles) return false;
 48→
 49→    if (Array.isArray(role)) {
 50→        return role.some(r => user.roles.includes(r));
 51→    }
 52→    return user.roles.includes(role);
 53→}
 54→
 55→/**
 56→ * Check if user is admin
 57→ */
 58→export function isAdmin(): boolean {
 59→    return hasRole('ADMIN');
 60→}
 61→
 62→/**
 63→ * Check if user has vulnerability management access (ADMIN, VULN, or SECCHAMPION role)
 64→ * Feature: 025-role-based-access-control - SECCHAMPION has broad access including vulns
 65→ */
 66→export function hasVulnAccess(): boolean {
 67→    return hasRole('ADMIN') || hasRole('VULN') || hasRole('SECCHAMPION');
 68→}
 69→
 70→/**
 71→ * Clear authentication data (logout).
 72→ * Note: The HttpOnly cookie is cleared by the /api/auth/logout endpoint.
 73→ * This function clears client-side data (user info and legacy token storage).
 74→ */
 75→export function clearAuth(): void {
 76→    if (typeof window === 'undefined') return;
 77→    // Clear user data
 78→    localStorage.removeItem('user');
 79→    // Clean up any legacy token storage from previous versions
 80→    localStorage.removeItem('authToken');
 81→    document.cookie = 'authToken=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT';
 82→}
 83→
 84→/**
 85→ * Make an authenticated API request.
 86→ * Authentication is handled via the HttpOnly secman_auth cookie sent automatically.
 87→ */
 88→export async function authenticatedFetch(url: string, options: RequestInit = {}): Promise<Response> {
 89→    const response = await fetch(url, {
 90→        ...options,
 91→        headers: {
 92→            'Content-Type': 'application/json',
 93→            ...options.headers,
 94→        },
 95→        credentials: 'include',
 96→    });
 97→
 98→    // If we get 401, clear auth data and redirect to login
 99→    if (response.status === 401) {
100→        clearAuth();
101→        if (typeof window !== 'undefined') {
102→            window.location.href = '/login';
103→        }
104→    }
105→
106→    return response;
107→}
108→
109→/**
110→ * Convenience method for GET requests
111→ */
112→export async function authenticatedGet(url: string): Promise<Response> {
113→    console.log('[auth] authenticatedGet called with URL:', url);
114→    const response = await authenticatedFetch(url, { method: 'GET' });
115→    console.log('[auth] authenticatedGet completed for URL:', url, 'status:', response.status);
116→    return response;
117→}
118→
119→/**
120→ * Convenience method for POST requests
121→ */
122→export async function authenticatedPost(url: string, data?: any): Promise<Response> {
123→    // Handle FormData (file uploads) differently - don't set Content-Type, let browser handle it
124→    if (data instanceof FormData) {
125→        const response = await fetch(url, {
126→            method: 'POST',
127→            body: data,
128→            credentials: 'include',
129→        });
130→
131→        if (response.status === 401) {
132→            clearAuth();
133→            if (typeof window !== 'undefined') {
134→                window.location.href = '/login';
135→            }
136→        }
137→
138→        return response;
139→    }
140→
141→    // For regular JSON data
142→    return authenticatedFetch(url, {
143→        method: 'POST',
144→        body: data ? JSON.stringify(data) : undefined,
145→    });
146→}
147→
148→/**
149→ * Convenience method for PUT requests
150→ */
151→export async function authenticatedPut(url: string, data?: any): Promise<Response> {
152→    return authenticatedFetch(url, {
153→        method: 'PUT',
154→        body: data ? JSON.stringify(data) : undefined,
155→    });
156→}
157→
158→/**
159→ * Convenience method for DELETE requests
160→ */
161→export async function authenticatedDelete(url: string): Promise<Response> {
162→    return authenticatedFetch(url, { method: 'DELETE' });
163→}
164→
165→// Session keep-alive configuration
166→const TOKEN_REFRESH_INTERVAL = 30 * 60 * 1000;  // 30 minutes
167→const HEARTBEAT_INTERVAL = 15 * 60 * 1000;       // 15 minutes
168→
169→let refreshIntervalId: number | null = null;
170→let heartbeatIntervalId: number | null = null;
171→
172→/**
173→ * Refresh the JWT token silently.
174→ * The token is stored in an HttpOnly cookie, so we use credentials: 'include'.
175→ * Returns true if successful, false otherwise.
176→ */
177→export async function refreshToken(): Promise<string | null> {
178→    // With HttpOnly cookies, we don't have direct access to the token
179→    // Check if user data exists (indicating a logged-in session)
180→    if (!isAuthenticated()) {
181→        return null;
182→    }
183→
184→    try {
185→        const response = await fetch('/api/auth/refresh', {
186→            method: 'POST',
187→            headers: {
188→                'Content-Type': 'application/json',
189→            },
190→            credentials: 'include', // Send HttpOnly cookie for authentication
191→        });
192→
193→        if (response.ok) {
194→            const data = await response.json();
195→            console.log('[auth] Token refreshed successfully (stored in HttpOnly cookie)');
196→            // Token is now in the updated HttpOnly cookie, not accessible via JS
197→            return data.token || 'refreshed';
198→        } else if (response.status === 401) {
199→            // Token is invalid/expired, clear auth and redirect
200→            console.log('[auth] Token refresh failed - session expired');
201→            clearAuth();
202→            if (typeof window !== 'undefined') {
203→                window.location.href = '/login';
204→            }
205→        }
206→    } catch (error) {
207→        console.error('[auth] Token refresh error:', error);
208→    }
209→
210→    return null;
211→}
212→
213→/**
214→ * Send a heartbeat to keep the session alive.
215→ * This validates the token without generating a new one.
216→ */
217→export async function sendHeartbeat(): Promise<boolean> {
218→    if (!isAuthenticated()) {
219→        return false;
220→    }
221→
222→    try {
223→        const response = await fetch('/api/auth/heartbeat', {
224→            method: 'GET',
225→            credentials: 'include', // Send HttpOnly cookie for authentication
226→        });
227→
228→        if (response.ok) {
229→            console.log('[auth] Heartbeat successful');
230→            return true;
231→        } else if (response.status === 401) {
232→            // Session expired, try to refresh
233→            console.log('[auth] Heartbeat failed - attempting token refresh');
234→            const newToken = await refreshToken();
235→            return newToken !== null;
236→        }
237→    } catch (error) {
238→        console.error('[auth] Heartbeat error:', error);
239→    }
240→
241→    return false;
242→}
243→
244→/**
245→ * Start the session keep-alive service.
246→ * This runs periodic heartbeats and token refreshes to prevent session timeout.
247→ */
248→export function startSessionKeepAlive(): void {
249→    if (typeof window === 'undefined') return;
250→
251→    // Stop any existing intervals
252→    stopSessionKeepAlive();
253→
254→    // Only start if authenticated
255→    if (!isAuthenticated()) {
256→        return;
257→    }
258→
259→    console.log('[auth] Starting session keep-alive service');
260→
261→    // Periodic heartbeat to validate session
262→    heartbeatIntervalId = window.setInterval(async () => {
263→        if (isAuthenticated()) {
264→            await sendHeartbeat();
265→        } else {
266→            stopSessionKeepAlive();
267→        }
268→    }, HEARTBEAT_INTERVAL);
269→
270→    // Periodic token refresh to extend session
271→    refreshIntervalId = window.setInterval(async () => {
272→        if (isAuthenticated()) {
273→            await refreshToken();
274→        } else {
275→            stopSessionKeepAlive();
276→        }
277→    }, TOKEN_REFRESH_INTERVAL);
278→}
279→
280→/**
281→ * Stop the session keep-alive service.
282→ */
283→export function stopSessionKeepAlive(): void {
284→    if (typeof window === 'undefined') return;
285→
286→    if (heartbeatIntervalId !== null) {
287→        window.clearInterval(heartbeatIntervalId);
288→        heartbeatIntervalId = null;
289→    }
290→
291→    if (refreshIntervalId !== null) {
292→        window.clearInterval(refreshIntervalId);
293→        refreshIntervalId = null;
294→    }
295→
296→    console.log('[auth] Session keep-alive service stopped');
297→}
298→
299→/**
300→ * Enhanced clearAuth that also stops keep-alive service.
301→ */
302→export function logout(): void {
303→    stopSessionKeepAlive();
304→    clearAuth();
305→}
