  7→/**
  8→ * Service for comprehensive input validation and sanitization
  9→ */
 10→@Singleton
 11→class InputValidationService {
 12→    
 13→    private val logger = LoggerFactory.getLogger(InputValidationService::class.java)
 14→    
 15→    companion object {
 16→        // Validation patterns
 17→        private val EMAIL_PATTERN = Pattern.compile(
 18→            "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$"
 19→        )
 20→        
 21→        private val PHONE_PATTERN = Pattern.compile(
 22→            "^[+]?[(]?[0-9]{1,4}[)]?[-\\s.]?[(]?[0-9]{1,4}[)]?[-\\s.]?[0-9]{1,9}$"
 23→        )
 24→        
 25→        private val ALPHANUMERIC_PATTERN = Pattern.compile("^[a-zA-Z0-9]+$")
 26→        
 27→        private val SAFE_TEXT_PATTERN = Pattern.compile("^[a-zA-Z0-9\\s.,!?@#$%^&*()_+=\\-\\[\\]{}|;:'\"`~<>/]+$")
 28→        
 29→        // SQL injection patterns
 30→        private val SQL_INJECTION_PATTERNS = listOf(
 31→            Pattern.compile("(\\b(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|CREATE|ALTER|EXEC|EXECUTE)\\b)", Pattern.CASE_INSENSITIVE),
 32→            Pattern.compile("(--|#|/\\*|\\*/|;\\s*--)", Pattern.CASE_INSENSITIVE),
 33→            Pattern.compile("(\\bOR\\b\\s+[\\w'\"]+\\s*=\\s*[\\w'\"]+)", Pattern.CASE_INSENSITIVE),
 34→            Pattern.compile("('[\"`;]\\s*(OR|AND)\\s+[\\w'\"]+\\s*=)", Pattern.CASE_INSENSITIVE)
 35→        )
 36→        
 37→        // XSS patterns
 38→        private val XSS_PATTERNS = listOf(
 39→            Pattern.compile("<script[^>]*>.*?</script>", Pattern.CASE_INSENSITIVE or Pattern.DOTALL),
 40→            Pattern.compile("javascript:", Pattern.CASE_INSENSITIVE),
 41→            Pattern.compile("on\\w+\\s*=", Pattern.CASE_INSENSITIVE),
 42→            Pattern.compile("<iframe[^>]*>", Pattern.CASE_INSENSITIVE),
 43→            Pattern.compile("<object[^>]*>", Pattern.CASE_INSENSITIVE),
 44→            Pattern.compile("<embed[^>]*>", Pattern.CASE_INSENSITIVE),
 45→            Pattern.compile("<applet[^>]*>", Pattern.CASE_INSENSITIVE)
 46→        )
 47→        
 48→        // Command injection patterns
 49→        private val COMMAND_INJECTION_PATTERNS = listOf(
 50→            Pattern.compile("[;&|`\$]"),
 51→            Pattern.compile("\\$\\([^)]*\\)"),
 52→            Pattern.compile("`[^`]*`")
 53→        )
 54→        
 55→        // Path traversal patterns
 56→        private val PATH_TRAVERSAL_PATTERNS = listOf(
 57→            Pattern.compile("\\.\\./"),
 58→            Pattern.compile("\\.\\.\\\\"),
 59→            Pattern.compile("%2e%2e[/\\\\]", Pattern.CASE_INSENSITIVE),
 60→            Pattern.compile("\\.\\.%2f", Pattern.CASE_INSENSITIVE)
 61→        )
 62→        
 63→        // Maximum lengths
 64→        const val MAX_NAME_LENGTH = 100
 65→        const val MAX_EMAIL_LENGTH = 255
 66→        const val MAX_DESCRIPTION_LENGTH = 5000
 67→        const val MAX_URL_LENGTH = 2048
 68→        const val MAX_PHONE_LENGTH = 20
 69→        const val MAX_ID_VALUE = 9999999999L
 70→    }
 71→    
 72→    /**
 73→     * Validate and sanitize email
 74→     */
 75→    fun validateEmail(email: String?): ValidationResult {
 76→        if (email.isNullOrBlank()) {
 77→            return ValidationResult(false, "Email is required")
 78→        }
 79→        
 80→        if (email.length > MAX_EMAIL_LENGTH) {
 81→            return ValidationResult(false, "Email is too long")
 82→        }
 83→        
 84→        if (!EMAIL_PATTERN.matcher(email).matches()) {
 85→            return ValidationResult(false, "Invalid email format")
 86→        }
 87→        
 88→        if (containsSqlInjection(email) || containsXss(email)) {
 89→            logger.warn("Potential injection attempt in email: {}", email)
 90→            return ValidationResult(false, "Invalid email format")
 91→        }
 92→        
 93→        return ValidationResult(true, sanitizeString(email))
 94→    }
 95→    
 96→    /**
 97→     * Validate and sanitize name fields
 98→     */
 99→    fun validateName(name: String?, fieldName: String = "Name"): ValidationResult {
100→        if (name.isNullOrBlank()) {
101→            return ValidationResult(false, "$fieldName is required")
102→        }
103→        
104→        if (name.length > MAX_NAME_LENGTH) {
105→            return ValidationResult(false, "$fieldName is too long")
106→        }
107→        
108→        if (containsSqlInjection(name) || containsXss(name)) {
109→            logger.warn("Potential injection attempt in {}: {}", fieldName, name)
110→            return ValidationResult(false, "$fieldName contains invalid characters")
111→        }
112→        
113→        return ValidationResult(true, sanitizeString(name))
114→    }
115→    
116→    /**
117→     * Validate and sanitize description/text fields
118→     */
119→    fun validateDescription(text: String?, fieldName: String = "Description"): ValidationResult {
120→        if (text == null) {
121→            return ValidationResult(true, "")
122→        }
123→        
124→        if (text.length > MAX_DESCRIPTION_LENGTH) {
125→            return ValidationResult(false, "$fieldName is too long")
126→        }
127→        
128→        if (containsSqlInjection(text) || containsXss(text)) {
129→            logger.warn("Potential injection attempt in {}: {}", fieldName, text.take(100))
130→            return ValidationResult(false, "$fieldName contains invalid content")
131→        }
132→        
133→        return ValidationResult(true, sanitizeString(text))
134→    }
135→    
136→    /**
137→     * Validate numeric ID
138→     */
139→    fun validateId(id: Long?): ValidationResult {
140→        if (id == null || id <= 0) {
141→            return ValidationResult(false, "Invalid ID")
142→        }
143→        
144→        if (id > MAX_ID_VALUE) {
145→            return ValidationResult(false, "ID value out of range")
146→        }
147→        
148→        return ValidationResult(true, id.toString())
149→    }
150→    
151→    /**
152→     * Validate URL
153→     */
154→    fun validateUrl(url: String?): ValidationResult {
155→        if (url.isNullOrBlank()) {
156→            return ValidationResult(false, "URL is required")
157→        }
158→        
159→        if (url.length > MAX_URL_LENGTH) {
160→            return ValidationResult(false, "URL is too long")
161→        }
162→        
163→        try {
164→            val uri = java.net.URI(url)
165→            if (uri.scheme !in setOf("http", "https")) {
166→                return ValidationResult(false, "Only HTTP and HTTPS URLs are allowed")
167→            }
168→        } catch (e: Exception) {
169→            return ValidationResult(false, "Invalid URL format")
170→        }
171→        
172→        if (containsSqlInjection(url) || containsXss(url)) {
173→            logger.warn("Potential injection attempt in URL: {}", url)
174→            return ValidationResult(false, "Invalid URL")
175→        }
176→        
177→        return ValidationResult(true, sanitizeString(url))
178→    }
179→    
180→    /**
181→     * Validate phone number
182→     */
183→    fun validatePhoneNumber(phone: String?): ValidationResult {
184→        if (phone.isNullOrBlank()) {
185→            return ValidationResult(true, "")
186→        }
187→        
188→        if (phone.length > MAX_PHONE_LENGTH) {
189→            return ValidationResult(false, "Phone number is too long")
190→        }
191→        
192→        if (!PHONE_PATTERN.matcher(phone).matches()) {
193→            return ValidationResult(false, "Invalid phone number format")
194→        }
195→        
196→        return ValidationResult(true, sanitizeString(phone))
197→    }
198→    
199→    /**
200→     * Validate alphanumeric string
201→     */
202→    fun validateAlphanumeric(input: String?, fieldName: String = "Field"): ValidationResult {
203→        if (input.isNullOrBlank()) {
204→            return ValidationResult(false, "$fieldName is required")
205→        }
206→        
207→        if (!ALPHANUMERIC_PATTERN.matcher(input).matches()) {
208→            return ValidationResult(false, "$fieldName must contain only letters and numbers")
209→        }
210→        
211→        return ValidationResult(true, input)
212→    }
213→    
214→    /**
215→     * Check for SQL injection patterns
216→     */
217→    private fun containsSqlInjection(input: String): Boolean {
218→        return SQL_INJECTION_PATTERNS.any { pattern ->
219→            pattern.matcher(input).find()
220→        }
221→    }
222→    
223→    /**
224→     * Check for XSS patterns
225→     */
226→    private fun containsXss(input: String): Boolean {
227→        return XSS_PATTERNS.any { pattern ->
228→            pattern.matcher(input).find()
229→        }
230→    }
231→    
232→    /**
233→     * Check for command injection patterns
234→     */
235→    fun containsCommandInjection(input: String): Boolean {
236→        return COMMAND_INJECTION_PATTERNS.any { pattern ->
237→            pattern.matcher(input).find()
238→        }
239→    }
240→    
241→    /**
242→     * Check for path traversal patterns
243→     */
244→    fun containsPathTraversal(input: String): Boolean {
245→        return PATH_TRAVERSAL_PATTERNS.any { pattern ->
246→            pattern.matcher(input).find()
247→        }
248→    }
249→    
250→    /**
251→     * Sanitize string by escaping HTML entities
252→     */
253→    fun sanitizeString(input: String): String {
254→        return input
255→            .replace("&", "&amp;")
256→            .replace("<", "&lt;")
257→            .replace(">", "&gt;")
258→            .replace("\"", "&quot;")
259→            .replace("'", "&#x27;")
260→            .replace("/", "&#x2F;")
261→            .replace("\u0000", "") // Remove null bytes
262→            .trim()
263→    }
264→    
265→    /**
266→     * Sanitize string for safe display (removes HTML but preserves text)
267→     */
268→    fun sanitizeForDisplay(input: String): String {
269→        return input
270→            .replace(Regex("<[^>]*>"), "") // Remove HTML tags
271→            .replace(Regex("javascript:", RegexOption.IGNORE_CASE), "")
272→            .replace(Regex("on\\w+\\s*=", RegexOption.IGNORE_CASE), "")
273→            .replace("\u0000", "") // Remove null bytes
274→            .trim()
275→    }
276→    
277→    /**
278→     * Validate JSON string
279→     */
280→    fun validateJson(json: String?): ValidationResult {
281→        if (json.isNullOrBlank()) {
282→            return ValidationResult(false, "JSON is required")
283→        }
284→        
285→        try {
286→            // Basic JSON validation
287→            com.fasterxml.jackson.databind.ObjectMapper().readTree(json)
288→        } catch (e: Exception) {
289→            return ValidationResult(false, "Invalid JSON format")
290→        }
291→        
292→        if (containsSqlInjection(json) || containsXss(json)) {
293→            logger.warn("Potential injection attempt in JSON")
294→            return ValidationResult(false, "JSON contains invalid content")
295→        }
296→        
297→        return ValidationResult(true, json)
298→    }
299→    
300→    /**
301→     * Validate list of IDs
302→     */
303→    fun validateIdList(ids: List<Long>?): ValidationResult {
304→        if (ids.isNullOrEmpty()) {
305→            return ValidationResult(false, "ID list is required")
306→        }
307→        
308→        if (ids.size > 1000) {
309→            return ValidationResult(false, "Too many IDs provided")
310→        }
311→        
312→        for (id in ids) {
313→            val result = validateId(id)
314→            if (!result.isValid) {
315→                return result
316→            }
317→        }
318→        
319→        return ValidationResult(true, ids.joinToString(","))
320→    }
321→    
322→    /**
323→     * Validate date string
324→     */
325→    fun validateDateString(date: String?, format: String = "yyyy-MM-dd"): ValidationResult {
326→        if (date.isNullOrBlank()) {
327→            return ValidationResult(false, "Date is required")
328→        }
329→        
330→        try {
331→            val formatter = java.time.format.DateTimeFormatter.ofPattern(format)
332→            java.time.LocalDate.parse(date, formatter)
333→        } catch (e: Exception) {
334→            return ValidationResult(false, "Invalid date format")
335→        }
336→        
337→        return ValidationResult(true, date)
338→    }
339→    
340→    /**
341→     * Result class for validation
342→     */
343→    data class ValidationResult(
344→        val isValid: Boolean,
345→        val sanitizedValue: String,
346→        val errorMessage: String? = null
347→    ) {
348→        constructor(isValid: Boolean, errorMessage: String) : this(isValid, "", errorMessage)
349→    }
350→}

 1→// Authentication initialization - call this on app startup
 2→
 3→export interface User {
 4→    id: number;
 5→    username: string;
 6→    email: string;
 7→    roles: string[];
 8→    workgroupCount?: number;
 9→    awsAccountCount?: number;
10→    domainCount?: number;
11→}
12→
13→declare global {
14→    interface Window {
15→        currentUser?: User | null;
16→    }
17→}
18→
19→/**
20→ * Initialize authentication state from localStorage
21→ * Should be called on app startup.
22→ *
23→ * Note: The JWT token is stored in an HttpOnly cookie (secman_auth)
24→ * for XSS protection. Only user data is stored in localStorage.
25→ */
26→export function initializeAuth(): void {
27→    try {
28→        const userStr = localStorage.getItem('user');
29→
30→        if (userStr) {
31→            const user = JSON.parse(userStr);
32→            window.currentUser = user;
33→            console.log('Auth initialized with user:', user);
34→        } else {
35→            window.currentUser = null;
36→            console.log('No authentication data found');
37→        }
38→
39→        // Dispatch event to notify components
40→        window.dispatchEvent(new CustomEvent('userLoaded'));
41→    } catch (error) {
42→        console.error('Failed to initialize auth:', error);
43→        // Clear invalid data
44→        localStorage.removeItem('user');
45→        window.currentUser = null;
46→        window.dispatchEvent(new CustomEvent('userLoaded'));
47→    }
48→}
49→
50→/**
51→ * Validate session by making a request to the backend.
52→ * Uses HttpOnly cookie for authentication (sent automatically with credentials: 'include').
53→ */
54→export async function validateToken(): Promise<boolean> {
55→    // Check if we have user data (indicates a logged-in session)
56→    const userStr = localStorage.getItem('user');
57→    if (!userStr) return false;
58→
59→    try {
60→        const response = await fetch('/api/auth/status', {
61→            method: 'GET',
62→            headers: {
63→                'Content-Type': 'application/json',
64→            },
65→            credentials: 'include',  // Send HttpOnly cookie automatically
66→        });
67→
68→        if (response.ok) {
69→            const userData = await response.json();
70→            // Update stored user data
71→            localStorage.setItem('user', JSON.stringify(userData));
72→            window.currentUser = userData;
73→            window.dispatchEvent(new CustomEvent('userLoaded'));
74→            return true;
75→        } else {
76→            // Session is invalid - clear user data
77→            localStorage.removeItem('user');
78→            window.currentUser = null;
79→            window.dispatchEvent(new CustomEvent('userLoaded'));
80→            return false;
81→        }
82→    } catch (error) {
83→        console.error('Token validation failed:', error);
84→        return false;
85→    }
86→}

