 1→// Authentication initialization - call this on app startup
 2→
 3→export interface User {
 4→    id: number;
 5→    username: string;
 6→    email: string;
 7→    roles: string[];
 8→    workgroupCount?: number;
 9→    awsAccountCount?: number;
10→    domainCount?: number;
11→}
12→
13→declare global {
14→    interface Window {
15→        currentUser?: User | null;
16→    }
17→}
18→
19→/**
20→ * Initialize authentication state from localStorage
21→ * Should be called on app startup.
22→ *
23→ * Note: The JWT token is stored in an HttpOnly cookie (secman_auth)
24→ * for XSS protection. Only user data is stored in localStorage.
25→ */
26→export function initializeAuth(): void {
27→    try {
28→        const userStr = localStorage.getItem('user');
29→
30→        if (userStr) {
31→            const user = JSON.parse(userStr);
32→            window.currentUser = user;
33→            console.log('Auth initialized with user:', user);
34→        } else {
35→            window.currentUser = null;
36→            console.log('No authentication data found');
37→        }
38→
39→        // Dispatch event to notify components
40→        window.dispatchEvent(new CustomEvent('userLoaded'));
41→    } catch (error) {
42→        console.error('Failed to initialize auth:', error);
43→        // Clear invalid data
44→        localStorage.removeItem('user');
45→        window.currentUser = null;
46→        window.dispatchEvent(new CustomEvent('userLoaded'));
47→    }
48→}
49→
50→/**
51→ * Validate session by making a request to the backend.
52→ * Uses HttpOnly cookie for authentication (sent automatically with credentials: 'include').
53→ */
54→export async function validateToken(): Promise<boolean> {
55→    // Check if we have user data (indicates a logged-in session)
56→    const userStr = localStorage.getItem('user');
57→    if (!userStr) return false;
58→
59→    try {
60→        const response = await fetch('/api/auth/status', {
61→            method: 'GET',
62→            headers: {
63→                'Content-Type': 'application/json',
64→            },
65→            credentials: 'include',  // Send HttpOnly cookie automatically
66→        });
67→
68→        if (response.ok) {
69→            const userData = await response.json();
70→            // Update stored user data
71→            localStorage.setItem('user', JSON.stringify(userData));
72→            window.currentUser = userData;
73→            window.dispatchEvent(new CustomEvent('userLoaded'));
74→            return true;
75→        } else {
76→            // Session is invalid - clear user data
77→            localStorage.removeItem('user');
78→            window.currentUser = null;
79→            window.dispatchEvent(new CustomEvent('userLoaded'));
80→            return false;
81→        }
82→    } catch (error) {
83→        console.error('Token validation failed:', error);
84→        return false;
85→    }
86→}

