 9→ */
10→export function setupCSRFProtection() {
11→  // Enable withCredentials globally so the HttpOnly secman_auth cookie
12→  // is sent with every axios request automatically
13→  axios.defaults.withCredentials = true;
14→
15→  // Get the CSRF token from meta tag
16→  const getCSRFToken = () => {
17→    const token = document.querySelector('meta[name="csrf-token"]')?.getAttribute('content');
18→    if (token) {
19→      return token;
20→    }
21→
22→    // Fallback: Get from cookies
23→    const csrfCookie = document.cookie.split(';')
24→      .find(cookie => cookie.trim().startsWith('PLAY_CSRF_TOKEN='));
25→    if (csrfCookie) {
26→      return csrfCookie.split('=')[1];
27→    }
28→
29→    return '';
30→  };
31→
32→  // Add CSRF token to all axios requests
33→  axios.interceptors.request.use(
34→    config => {
35→      const token = getCSRFToken();
36→      // Ensure headers object exists
37→      config.headers = config.headers ?? {};
38→      if (token) {
39→        // Only use the header name that matches the backend configuration
40→        config.headers['Csrf-Token'] = token;
41→      }
42→
43→      return config;
44→    },
45→    error => Promise.reject(error)
46→  );
47→}
