package com.secman.util

import jakarta.persistence.AttributeConverter
import jakarta.persistence.Converter
import org.springframework.security.crypto.encrypt.Encryptors
import org.springframework.security.crypto.encrypt.TextEncryptor
import java.security.SecureRandom
import java.util.*

@Converter
class EncryptedStringConverter : AttributeConverter<String?, String?> {

    companion object {
        private const val ENCRYPTION_PASSWORD_PROPERTY = "secman.encryption.password"
        private const val ENCRYPTION_SALT_PROPERTY = "secman.encryption.salt"

        // Default values for development - should be overridden in production
        private const val DEFAULT_PASSWORD = "SecManDefaultEncryptionPassword2024"
        private const val DEFAULT_SALT = "5c0744940b5c369b"

        private val textEncryptor: TextEncryptor by lazy {
            val password = System.getProperty(ENCRYPTION_PASSWORD_PROPERTY)
                ?: System.getenv("SECMAN_ENCRYPTION_PASSWORD")
                ?: DEFAULT_PASSWORD

            val salt = System.getProperty(ENCRYPTION_SALT_PROPERTY)
                ?: System.getenv("SECMAN_ENCRYPTION_SALT")
                ?: DEFAULT_SALT

            Encryptors.text(password, salt)
        }

        /**
         * Generate a random salt for production use
         */
        fun generateSalt(): String {
            val bytes = ByteArray(8)
            SecureRandom().nextBytes(bytes)
            return bytes.joinToString("") { String.format("%02x", it) }
        }

        /**
         * Generate a random password for production use
         */
        fun generatePassword(): String {
            val bytes = ByteArray(32)
            SecureRandom().nextBytes(bytes)
            return Base64.getEncoder().encodeToString(bytes)
        }
    }

    /**
     * Convert the entity attribute to a database column value.
     * Encrypts the plaintext string for storage.
     */
    override fun convertToDatabaseColumn(attribute: String?): String? {
        return attribute?.let { plaintext ->
            try {
                textEncryptor.encrypt(plaintext)
            } catch (e: Exception) {
                throw RuntimeException("Failed to encrypt sensitive data", e)
            }
        }
    }

    /**
     * Convert the database column value to an entity attribute.
     * Decrypts the encrypted string for use in the application.
     */
    override fun convertToEntityAttribute(dbData: String?): String? {
        return dbData?.let { encrypted ->
            try {
                textEncryptor.decrypt(encrypted)
            } catch (e: Exception) {
                throw RuntimeException("Failed to decrypt sensitive data. " +
                    "This may indicate corrupted data or mismatched encryption keys.", e)
            }
        }
    }
}

package com.secman.filter

import io.micronaut.http.HttpRequest
import io.micronaut.http.MutableHttpResponse
import io.micronaut.http.annotation.Filter
import io.micronaut.http.filter.HttpServerFilter
import io.micronaut.http.filter.ServerFilterChain
import io.micronaut.http.filter.ServerFilterPhase
import org.reactivestreams.Publisher
import reactor.core.publisher.Flux
import org.slf4j.LoggerFactory

/**
 * Security headers filter to add comprehensive security headers to all responses.
 *
 * SECURITY DOCUMENTATION:
 *
 * Content Security Policy (CSP) Configuration:
 * - 'unsafe-inline' is REQUIRED for Astro's hydration scripts and React islands
 * - Full nonce-based CSP migration requires frontend changes:
 *   1. Backend: Generate per-request nonce and pass to templates
 *   2. Frontend: Add nonce="..." to all <script> and <style> tags
 *   3. Update Astro config to support nonce injection
 * - Current mitigation: strict-dynamic is NOT used because it requires nonces
 *
 * To migrate to nonce-based CSP (recommended for higher security):
 * 1. Create NonceProvider singleton that generates cryptographic nonces
 * 2. Add nonce to response attributes in this filter
 * 3. Update Astro/React to read nonce from response context
 * 4. Replace 'unsafe-inline' with 'nonce-{value}'
 */
@Filter("/**")
class SecurityHeadersFilter : HttpServerFilter {

    private val logger = LoggerFactory.getLogger(SecurityHeadersFilter::class.java)

    companion object {
        // Content Security Policy - Hardened policy to prevent XSS
        // SECURITY: 'unsafe-inline' is required for Astro framework compatibility
        // See class documentation for nonce-based CSP migration plan
        private const val CSP_POLICY = "default-src 'self'; " +
            "script-src 'self' 'unsafe-inline' https://cdn.jsdelivr.net; " +  // Removed unsafe-eval
            "style-src 'self' 'unsafe-inline' https://cdn.jsdelivr.net; " +
            "img-src 'self' data: https:; " +
            "font-src 'self' data: https://cdn.jsdelivr.net; " +
            "connect-src 'self'; " +
            "frame-ancestors 'none'; " +
            "form-action 'self'; " +
            "base-uri 'self'; " +
            "object-src 'none'; " +
            "upgrade-insecure-requests"

        // Permissions Policy (formerly Feature Policy) - disable all risky APIs
        private const val PERMISSIONS_POLICY = "geolocation=(), " +
            "microphone=(), " +
            "camera=(), " +
            "payment=(), " +
            "usb=(), " +
            "magnetometer=(), " +
            "gyroscope=(), " +
            "accelerometer=()"

        // Cross-Origin policies for additional isolation
        private const val CROSS_ORIGIN_EMBEDDER_POLICY = "require-corp"
        private const val CROSS_ORIGIN_OPENER_POLICY = "same-origin"
        private const val CROSS_ORIGIN_RESOURCE_POLICY = "same-origin"
    }

    override fun doFilter(request: HttpRequest<*>, chain: ServerFilterChain): Publisher<MutableHttpResponse<*>> {
        return Flux.from(chain.proceed(request))
            .map { response ->
                addSecurityHeaders(response, request)
                response
            }
    }

    private fun addSecurityHeaders(response: MutableHttpResponse<*>, request: HttpRequest<*>) {
        // Prevent clickjacking attacks
        response.header("X-Frame-Options", "DENY")

        // Prevent MIME type sniffing
        response.header("X-Content-Type-Options", "nosniff")

        // Enable XSS protection in older browsers
        response.header("X-XSS-Protection", "1; mode=block")

        // Control referrer information
        response.header("Referrer-Policy", "strict-origin-when-cross-origin")

        // Content Security Policy
        response.header("Content-Security-Policy", CSP_POLICY)

        // Permissions Policy
        response.header("Permissions-Policy", PERMISSIONS_POLICY)

        // Cross-Origin Isolation headers for defense-in-depth
        // These headers prevent various cross-origin attacks
        // Excluded for OAuth paths: COOP/CORP interfere with cross-origin redirect chains
        // (secman → Microsoft/Google → secman) in some browsers
        if (!request.uri.path.startsWith("/oauth/")) {
            response.header("Cross-Origin-Opener-Policy", CROSS_ORIGIN_OPENER_POLICY)
            response.header("Cross-Origin-Resource-Policy", CROSS_ORIGIN_RESOURCE_POLICY)
        }

        // Strict Transport Security (HSTS) - only for HTTPS
        if (request.uri.scheme == "https") {
            response.header("Strict-Transport-Security", "max-age=31536000; includeSubDomains; preload")
        }

        // Remove server header to avoid information disclosure
        response.headers.remove("Server")
        response.headers.remove("X-Powered-By")

        // Add custom security header
        response.header("X-Security-Policy", "enabled")

        // Cache control for sensitive data (API endpoints)
        if (request.uri.path.startsWith("/api/")) {
            response.header("Cache-Control", "no-store, no-cache, must-revalidate, private")
            response.header("Pragma", "no-cache")
            response.header("Expires", "0")
        }

        // SSE endpoints: disable proxy buffering and keep connection alive
        // X-Accel-Buffering: no — prevents nginx from buffering SSE responses
        // Connection: keep-alive — signals proxies (F5, ALB) to maintain the TCP connection
        if (request.uri.path == "/api/exception-badge-updates" ||
            request.uri.path == "/api/materialized-view-refresh/progress") {
            response.header("X-Accel-Buffering", "no")
            response.header("Connection", "keep-alive")
        }

        // AGGRESSIVE cache control for OAuth endpoints to prevent "state" errors
        // in corporate AAD environments where cached responses cause state mismatches
        if (request.uri.path.startsWith("/oauth/")) {
            response.header("Cache-Control", "no-store, no-cache, must-revalidate, max-age=0")
            response.header("Pragma", "no-cache")
            response.header("Expires", "0")
        }
    }

    override fun getOrder(): Int {
        // Run early in the filter chain
        return ServerFilterPhase.SECURITY.order()
    }
}

package com.secman.controller

import com.secman.domain.Requirement
import com.secman.repository.RequirementRepository
import com.secman.repository.UseCaseRepository
import io.micronaut.core.annotation.Nullable
import io.micronaut.http.HttpResponse
import io.micronaut.http.MediaType
import io.micronaut.http.annotation.*
import io.micronaut.http.server.types.files.StreamedFile
import io.micronaut.security.annotation.Secured
import io.micronaut.security.rules.SecurityRule
import io.micronaut.serde.annotation.Serdeable
import org.apache.poi.xwpf.usermodel.BreakType
import org.apache.poi.xwpf.usermodel.ParagraphAlignment
import org.apache.poi.xwpf.usermodel.XWPFDocument
import java.io.ByteArrayInputStream
import java.io.ByteArrayOutputStream
import java.time.LocalDateTime
import java.time.format.DateTimeFormatter

@Controller("/api/reqdl")
@Secured(SecurityRule.IS_ANONYMOUS)
open class PublicRequirementDownloadController(
    private val requirementRepository: RequirementRepository,
    private val useCaseRepository: UseCaseRepository
) {

    @Serdeable
    data class UseCaseDto(val id: Long, val name: String)

    @Get("/usecases")
    fun listUseCases(): HttpResponse<List<UseCaseDto>> {
        val useCases = useCaseRepository.findAll()
            .map { UseCaseDto(it.id!!, it.name) }
            .sortedBy { it.name }
        return HttpResponse.ok(useCases)
    }

    @Get("/export/docx")
    fun exportToDocx(@Nullable @QueryValue("usecaseIds") usecaseIds: String?): HttpResponse<*> {
        val requirements: List<Requirement>
        val title: String
        val filenameSuffix: String

        if (!usecaseIds.isNullOrBlank()) {
            val ids = usecaseIds.split(",").mapNotNull { it.trim().toLongOrNull() }
            if (ids.isEmpty()) {
                return HttpResponse.badRequest(mapOf("error" to "Invalid use case IDs"))
            }

            val useCases = ids.mapNotNull { id -> useCaseRepository.findById(id).orElse(null) }
            if (useCases.isEmpty()) {
                return HttpResponse.notFound(mapOf("error" to "No valid use cases found"))
            }

            val useCaseNames = useCases.map { it.name }

            // Get requirements that have at least one of the selected use cases
            val reqSet = mutableSetOf<Long>()
            val allReqs = mutableListOf<Requirement>()
            for (id in ids) {
                for (req in requirementRepository.findByUsecaseId(id)) {
                    if (reqSet.add(req.id!!)) {
                        allReqs.add(req)
                    }
                }
            }

            requirements = allReqs.sortedWith(
                compareBy<Requirement> { it.chapter ?: "" }.thenBy { it.id ?: 0 }
            )
            title = "Requirements - ${useCaseNames.joinToString(", ")}"
            filenameSuffix = "_${useCaseNames.joinToString("_") { it.replace(" ", "") }}"
        } else {
            requirements = requirementRepository.findAll().sortedWith(
                compareBy<Requirement> { it.chapter ?: "" }.thenBy { it.id ?: 0 }
            )
            title = "All Requirements"
            filenameSuffix = ""
        }

        if (requirements.isEmpty()) {
            return HttpResponse.ok(mapOf("message" to "No requirements found"))
        }

        val document = createWordDocument(requirements, title)
        val outputStream = ByteArrayOutputStream()
        document.write(outputStream)
        document.close()

        val dateStr = LocalDateTime.now().format(DateTimeFormatter.ofPattern("yyyyMMdd"))
        val filename = "requirements${filenameSuffix}_$dateStr.docx"
            .replace("\"", "").replace("\r", "").replace("\n", "")
        val inputStream = ByteArrayInputStream(outputStream.toByteArray())

        return HttpResponse.ok(StreamedFile(inputStream, MediaType.of("application/vnd.openxmlformats-officedocument.wordprocessingml.document")))
            .header("Content-Disposition", "attachment; filename=\"$filename\"")
    }

    private fun createWordDocument(requirements: List<Requirement>, title: String): XWPFDocument {
        val document = XWPFDocument()

        // Title
        val titleParagraph = document.createParagraph()
        titleParagraph.alignment = ParagraphAlignment.CENTER
        val titleRun = titleParagraph.createRun()
        titleRun.setText(title)
        titleRun.fontSize = 18
        titleRun.isBold = true

        // Generation date
        val dateParagraph = document.createParagraph()
        dateParagraph.alignment = ParagraphAlignment.CENTER
        val dateRun = dateParagraph.createRun()
        dateRun.setText("Generated on: ${LocalDateTime.now().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"))}")

        document.createParagraph()

        // Table of Contents placeholder
        val tocParagraph = document.createParagraph()
        val tocRun = tocParagraph.createRun()
        tocRun.setText("Table of Contents")
        tocRun.fontSize = 14
        tocRun.isBold = true

        val tocFieldParagraph = document.createParagraph()
        val tocFieldRun = tocFieldParagraph.createRun()
        tocFieldRun.setText("(Please update this field manually in Word: right-click → Update Field)")

        // Page break
        document.createParagraph().createRun().addBreak(BreakType.PAGE)

        // Group requirements by chapter
        val requirementsByChapter = requirements.groupBy { it.chapter ?: "No Chapter" }

        var isFirstChapter = true
        for ((chapter, chapterRequirements) in requirementsByChapter) {
            if (!isFirstChapter) {
                document.createParagraph().createRun().addBreak(BreakType.PAGE)
            }
            isFirstChapter = false

            // Chapter heading
            val chapterParagraph = document.createParagraph()
            chapterParagraph.style = "Heading1"
            val chapterRun = chapterParagraph.createRun()
            chapterRun.setText(chapter)
            chapterRun.fontSize = 16
            chapterRun.isBold = true

            document.createParagraph()

            for (requirement in chapterRequirements) {
                // Requirement header with light green background
                val reqHeaderParagraph = document.createParagraph()
                val ctp = reqHeaderParagraph.ctp
                val ppr = if (ctp.isSetPPr) ctp.pPr else ctp.addNewPPr()
                val shd = if (ppr.isSetShd) ppr.shd else ppr.addNewShd()
                shd.fill = "C1D5C0"

                val reqHeaderRun = reqHeaderParagraph.createRun()
                reqHeaderRun.setText("${requirement.internalId}: ${requirement.shortreq}")
                reqHeaderRun.fontSize = 12
                reqHeaderRun.isBold = true

                // Details
                requirement.details?.let { details ->
                    val detailsParagraph = document.createParagraph()
                    val detailsRun = detailsParagraph.createRun()
                    detailsRun.setText(details)
                }

                // Motivation
                requirement.motivation?.let { motivation ->
                    val motivationParagraph = document.createParagraph()
                    val motivationLabelRun = motivationParagraph.createRun()
                    motivationLabelRun.setText("Motivation: ")
                    motivationLabelRun.isBold = true
                    val motivationValueRun = motivationParagraph.createRun()
                    motivationValueRun.setText(motivation)
                }

                // Example
                requirement.example?.let { example ->
                    val exampleParagraph = document.createParagraph()
                    val exampleLabelRun = exampleParagraph.createRun()
                    exampleLabelRun.setText("Example: ")
                    exampleLabelRun.isBold = true
                    val exampleValueRun = exampleParagraph.createRun()
                    exampleValueRun.setText(example)
                }

                // Norm reference
                requirement.norm?.let { norm ->
                    val normParagraph = document.createParagraph()
                    val normLabelRun = normParagraph.createRun()
                    normLabelRun.setText("Norm Reference: ")
                    normLabelRun.isBold = true
                    val normValueRun = normParagraph.createRun()
                    normValueRun.setText(norm)
                }

                // Internal ID with use cases
                val canonicalUseCases = setOf("IT", "OT", "NT")
                val idSuffix = buildString {
                    append(requirement.internalId.removePrefix("REQ-"))
                    append(".")
                    append(requirement.versionNumber)
                    val usecaseNames = requirement.usecases
                        .map { it.name }
                        .filter { it in canonicalUseCases }
                        .sorted()
                    for (uc in usecaseNames) {
                        append(".")
                        append(uc)
                    }
                }
                val idParagraph = document.createParagraph()
                idParagraph.alignment = ParagraphAlignment.LEFT
                val idRun = idParagraph.createRun()
                idRun.setText("ID $idSuffix")
                idRun.fontSize = 8
                idRun.color = "999999"

                document.createParagraph()
            }
        }

        return document
    }
}

package com.secman.config

import com.secman.domain.User
import com.secman.repository.UserRepository
import io.micronaut.context.event.ApplicationEventListener
import io.micronaut.runtime.event.ApplicationStartupEvent
import io.micronaut.context.annotation.Requires
import io.micronaut.transaction.annotation.Transactional
import jakarta.inject.Singleton
import org.slf4j.LoggerFactory
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder

/**
 * Creates a default admin user on first application startup if no users exist.
 *
 * Default credentials:
 *   Username: admin
 *   Email:    admin@localhost
 *   Password: password
 *   Roles:    ADMIN, USER
 *
 * IMPORTANT: Change the default password immediately after first login in production.
 */
@Requires(notEnv = ["cli"])
@Singleton
open class DefaultAdminBootstrapper(
    private val userRepository: UserRepository
) : ApplicationEventListener<ApplicationStartupEvent> {

    private val log = LoggerFactory.getLogger(DefaultAdminBootstrapper::class.java)
    private val passwordEncoder = BCryptPasswordEncoder()

    companion object {
        const val DEFAULT_ADMIN_USERNAME = "admin"
        const val DEFAULT_ADMIN_EMAIL = "admin@localhost"
        const val DEFAULT_ADMIN_PASSWORD = "password"
    }

    override fun onApplicationEvent(event: ApplicationStartupEvent) {
        bootstrapDefaultAdmin()
    }

    @Transactional
    open fun bootstrapDefaultAdmin() {
        try {
            val userCount = userRepository.count()
            if (userCount > 0) {
                log.debug("Users already exist (count={}), skipping default admin creation", userCount)
                return
            }

            val admin = User(
                username = DEFAULT_ADMIN_USERNAME,
                email = DEFAULT_ADMIN_EMAIL,
                passwordHash = passwordEncoder.encode(DEFAULT_ADMIN_PASSWORD)!!,
                roles = mutableSetOf(User.Role.ADMIN, User.Role.USER),
                authSource = User.AuthSource.LOCAL
            )

            userRepository.save(admin)
            log.warn("==========================================================")
            log.warn("  DEFAULT ADMIN USER CREATED")
            log.warn("  Username: {}", DEFAULT_ADMIN_USERNAME)
            log.warn("  Password: {} (CHANGE IMMEDIATELY!)", DEFAULT_ADMIN_PASSWORD)
            log.warn("==========================================================")
        } catch (e: Exception) {
            log.error("Failed to bootstrap default admin user: {}", e.message, e)
        }
    }
}

    }

    /**
     * GET /api/aws-account-sharing/users - Lightweight user list for the sharing form.
     * Returns minimal user info (id, username, email) for populating target user dropdowns.
     * Available to all authenticated users so non-admins can select sharing targets.
     */
    @Get("/users")
    fun listUsersForSharing(): HttpResponse<List<SharingUserResponse>> {
        val users = userRepository.findAll().map { user ->
            SharingUserResponse(
                id = user.id!!,
                username = user.username,
                email = user.email
            )
        }
        return HttpResponse.ok(users)
    }

    private fun isAdmin(authentication: Authentication): Boolean {
        return authentication.roles.contains("ADMIN")
    }

    @Serdeable
    data class SharingUserResponse(
        val id: Long,
        val username: String,
        val email: String
    )
}
